147→					<ProjectTrendChart data={trendData} maxProjects={10} />
148→				</AnalyticsCard>
149→			)}
150→
151→			<AnalyticsCard>
152→				<h2 className="text-xl font-bold text-heading mb-4">Project Details</h2>
153→				{projects && projects.length > 0 ? (
154→					<Table>
155→						<TableHeader className="bg-surface">
156→							<TableRow>
157→								<TableHead className="px-6 py-3 text-xs text-muted uppercase tracking-wider">
158→									Project
159→								</TableHead>
160→								<TableHead className="px-6 py-3 text-xs text-muted uppercase tracking-wider">
161→									Sessions
162→								</TableHead>
163→								<TableHead className="px-6 py-3 text-xs text-muted uppercase tracking-wider">
164→									Time
165→								</TableHead>
166→								<TableHead className="px-6 py-3 text-xs text-muted uppercase tracking-wider">
167→									Tokens
168→								</TableHead>
169→								<TableHead className="px-6 py-3 text-xs text-muted uppercase tracking-wider">
170→									Success Rate
171→								</TableHead>
172→								<TableHead className="px-6 py-3 text-xs text-muted uppercase tracking-wider">
173→									Cost
174→								</TableHead>
175→								<TableHead className="px-6 py-3 text-xs text-muted uppercase tracking-wider">
176→									Trend
177→								</TableHead>
178→							</TableRow>
179→						</TableHeader>
180→						<TableBody className="bg-input">
181→							{projects.map((project, index) => {
182→								const encodedPath = encodeProjectPath(project.project_path);
183→								const successRate = project.success_rate || 0;
184→								const successRateColor =
185→									successRate >= 70
186→										? "text-status-success-icon"
187→										: successRate >= 50
188→											? "text-status-warning-icon"
189→											: "text-status-error-icon";
190→								const trend = project.success_rate_trend || 0;
191→								const trendIconStr =
192→									trend > 0 ? "\u2191" : trend < 0 ? "\u2193" : "-";
193→								const trendColor =
194→									trend > 0
195→										? "text-status-success-icon"
196→										: trend < 0
197→											? "text-status-error-icon"
198→											: "text-muted";
199→
200→								return (
201→									<TableRow
202→										// biome-ignore lint/suspicious/noArrayIndexKey: static project list
203→										key={index}
204→										onClick={() =>
205→											navigate(`/dashboard/projects/${encodedPath}`)
206→										}
207→										className="hover:bg-hover cursor-pointer"
208→									>
209→										<TableCell className="px-6 py-4 text-sm font-medium text-foreground">
210→											{project.project_path.split("/").pop()}
211→										</TableCell>
212→										<TableCell className="px-6 py-4 text-sm text-muted">
213→											{project.sessions}
214→										</TableCell>
215→										<TableCell className="px-6 py-4 text-sm text-muted">
216→											{(project.total_duration_min / 60).toFixed(1)}h
217→										</TableCell>
218→										<TableCell className="px-6 py-4 text-sm text-muted">
219→											{formatTokens(project.total_tokens || 0)}
220→										</TableCell>
221→										<TableCell
222→											className={`px-6 py-4 text-sm font-semibold ${successRateColor}`}
223→										>
224→											{successRate.toFixed(0)}%
225→										</TableCell>
226→										<TableCell className="px-6 py-4 text-sm text-muted">
227→											${(project.cost || 0).toFixed(2)}
228→										</TableCell>
229→										<TableCell
230→											className={`px-6 py-4 text-sm font-semibold ${trendColor}`}
231→										>
232→											{trendIconStr} {Math.abs(trend).toFixed(1)}%
233→										</TableCell>
234→									</TableRow>
235→								);
236→							})}
237→						</TableBody>
238→					</Table>
239→				) : (
